-- RIASEC: R=(3.8+3.5+3.2)/3=3.5, I=(4.5+4.3+4.0+3.8)/4=4.15, A=(2.5+2.3+2.0)/3=2.27, S=(1.8+2.8+2.8+3.5)/4=2.73, E=(2.3+2.0+1.8)/3=2.03, C=(3.0+2.8+2.5)/3=2.77
ON CONFLICT DO NOTHING;



-- user_skills: 全ユーザーにスキルを紐付け
SELECT u.id, s.id
FROM users u
CROSS JOIN LATERAL (
  SELECT id FROM skills ORDER BY random() LIMIT 3 + (random() * 2)::int
) s
WHERE u.id NOT IN (SELECT DISTINCT user_id FROM user_skills)
ON CONFLICT DO NOTHING;

